xf:setvalue.value:
if ($is-form-event) then
    'fr-form-model'
else
    string-join(
        for $c in xxf:split(string($instance/fb:listener/@controls))
        return concat($c, '-control'),
        ' '
    )

xf:var.value:
if (starts-with($ref-attr, '//') and not(contains(substring-after($ref-attr, '//'), '/')))
    then substring-after($ref-attr, '//')
else if (starts-with($ref-attr, '/*/') and not(contains(substring-after($ref-attr, '/*/'), '/')))
    then substring-after($ref-attr, '/*/')
else ''

xf:insert.origin:
xf:element('fr:url-param', (
    xf:attribute('name', $param-name-from-path),
    if (exists($control-attr-opt)) then xf:attribute('control', $control-attr-opt) else (),
    if (exists($value-attr-opt))   then xf:attribute('value',   $value-attr-opt)   else (),
    xf:element('dropdown-value', concat('p:', '''', $param-name-from-path, ''''))
))

xf:element('fr:value', (
    xf:attribute('ref', concat('//', $param-name)),
    if (exists($control-attr-opt)) then xf:attribute('control', $control-attr-opt) else (),
    if (exists($value-attr-opt))   then xf:attribute('value',   $value-attr-opt)   else ()
))

xf:var.value:
instance('fb-binding-action-template')/*[
    if ($use-param-template)
    then self::fr:url-param
    else self::fr:value
][1]

xf:insert.origin:
xf:element('fr:header', (
    xf:attribute('name', $bare-name),
    if (exists($ctrl-attr-opt))  then xf:attribute('control', $ctrl-attr-opt)  else (),
    if (exists($value-attr-opt)) then xf:attribute('value',   $value-attr-opt) else ()
))

xf:element('fr:url-param', (
    xf:attribute('name', $bare-name),
    if (exists($ctrl-attr-opt))  then xf:attribute('control', $ctrl-attr-opt)  else (),
    if (exists($value-attr-opt)) then xf:attribute('value',   $value-attr-opt) else ()
))

xf:var.value:
string-join(
    for $o in xxf:split(string($observer))
    return
        if (ends-with($o, '-control'))
        then substring($o, 1, string-length($o) - string-length('-control'))
        else $o,
    ' ')
